function grpcStatusToHttp(grpcStatus) {
  const statusMap = {
    [grpc.status.OK]: 200,
    [grpc.status.CANCELLED]: 499,
    [grpc.status.INVALID_ARGUMENT]: 400,
    [grpc.status.DEADLINE_EXCEEDED]: 504,
    [grpc.status.NOT_FOUND]: 404,
    [grpc.status.ALREADY_EXISTS]: 409,
    [grpc.status.PERMISSION_DENIED]: 403,
    [grpc.status.RESOURCE_EXHAUSTED]: 429,
    [grpc.status.FAILED_PRECONDITION]: 400,
    [grpc.status.ABORTED]: 409,
    [grpc.status.OUT_OF_RANGE]: 400,
    [grpc.status.UNIMPLEMENTED]: 501,
    [grpc.status.INTERNAL]: 500,
    [grpc.status.UNAVAILABLE]: 503,
    [grpc.status.DATA_LOSS]: 500,
    [grpc.status.UNAUTHENTICATED]: 401
  };
  
  return statusMap[grpcStatus] || 500;
}

class GrpcGateway {
  constructor(protoPath, grpcServerAddress) {
    this.protoPath = protoPath;
    this.grpcServerAddress = grpcServerAddress;
    this.clients = new Map();
    
    const packageDef = protoLoader.loadSync(this.protoPath, {
      keepCase: true,
      longs: String,
      enums: String,
      defaults: true,
      oneofs: true
    });
    
    this.proto = grpc.loadPackageDefinition(packageDef);
  }
  
  getClient(serviceName) {
    if (this.clients.has(serviceName)) {
      return this.clients.get(serviceName);
    }
    
    const serviceDefinition = this.proto[serviceName];
    if (!serviceDefinition) {
      throw new Error(`Service ${serviceName} not found`);
    }
    
    const client = new serviceDefinition(
      this.grpcServerAddress,
      grpc.credentials.createInsecure()
    );
    
    this.clients.set(serviceName, client);
    return client;
  }
  
  async call(serviceName, methodName, requestData, httpHeaders) {
    return new Promise((resolve, reject) => {
      const client = this.getClient(serviceName);
      const metadata = createGrpcMetadata(httpHeaders);
      
      if (typeof client[methodName] !== 'function') {
        return reject(new Error(`Method ${methodName} not found`));
      }
      
      client[methodName](requestData, metadata, (error, response) => {
        if (error) {
          return reject(error);
        }
        resolve(response);
      });
    });
  }
  
  async callWithDeadline(serviceName, methodName, requestData, httpHeaders, deadlineMs = 5000) {
    return new Promise((resolve, reject) => {
      const client = this.getClient(serviceName);
      const metadata = createGrpcMetadata(httpHeaders);
      
      if (typeof client[methodName] !== 'function') {
        return reject(new Error(`Method ${methodName} not found`));
      }
      
      const deadline = new Date();
      deadline.setMilliseconds(deadline.getMilliseconds() + deadlineMs);
      
      client[methodName](requestData, metadata, { deadline }, (error, response) => {
        if (error) {
          return reject(error);
        }
        resolve(response);
      });
    });
  }
}

const gateway = new GrpcGateway(PROTO_PATH, GRPC_SERVER);

app.post('/gateway/:service/:method', async (req, res) => {
  try {
    const { service, method } = req.params;
    const deadline = parseInt(req.headers['x-deadline-ms']) || 5000;
    
    const response = await gateway.callWithDeadline(
      service,
      method,
      req.body,
      req.headers,
      deadline
    );
    
    res.json(response);
  } catch (error) {
    const statusCode = grpcStatusToHttp(error.code || grpc.status.INTERNAL);
    res.status(statusCode).json({
      error: error.message,
      code: error.code,
      details: error.details
    });
  }
});

